#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);
use CGI::Carp qw(fatalsToBrowser);

my $log_dir = '/path/to/log/files'; # Change this to your log directory
my $cgi = CGI->new;
print $cgi->header;

my $filename = $cgi->param('logfile');
my $filepath = "$log_dir/$filename";

if (defined $filename && $filename =~ /^[\w\-.]+$/) {  
    if (open(my $FH, '<', $filepath)) {
        print $cgi->start_html("Log Viewer");
        print $cgi->h1("Viewing Log: $filename");
        print $cgi->pre(<$FH>);
        close($FH);
        print $cgi->end_html;
    } else {
        print $cgi->h1("Error opening file: $!");
    }
} else {
    print $cgi->h1("Invalid filename specified.");
}